public final class EncryptedFileStorage: SecureStorage, @unchecked Sendable {
    private let crypto: SecureCrypto
    private let fileURL: URL
    private let aad: Data

    public init(filename: String = "ledger.enc.json",
                crypto: SecureCrypto = SecureCrypto()) {
        self.crypto = crypto
        let fm = FileManager.default
        let dir = fm.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        if !fm.fileExists(atPath: dir.path) {
            try? fm.createDirectory(at: dir, withIntermediateDirectories: true)
        }
        self.fileURL = dir.appendingPathComponent(filename)
        self.aad = Data((Bundle.main.bundleIdentifier ?? "com.example.banking").utf8)
    }

    public func load() throws -> LedgerSnapshot {
        guard FileManager.default.fileExists(atPath: fileURL.path) else {
            return LedgerSnapshot()
        }
        let encrypted = try Data(contentsOf: fileURL, options: [.mappedIfSafe])
        let plaintext = try crypto.decrypt(encrypted, aad: aad)
        return try JSONDecoder().decode(LedgerSnapshot.self, from: plaintext)
    }

    public func save(_ snapshot: LedgerSnapshot) throws {
        let plaintext = try JSONEncoder().encode(snapshot)
        let encrypted = try crypto.encrypt(plaintext, aad: aad)
        do {
            try encrypted.write(to: fileURL, options: [.atomic, .completeFileProtection])
        } catch {
            throw BankingError.persistenceFailure
        }
    }

    public func wipe() throws {
        if FileManager.default.fileExists(atPath: fileURL.path) {
            try FileManager.default.removeItem(at: fileURL)
        }
    }
}

