// MARK: - Transaction Processing

public protocol TransactionProcessor: Sendable {
    func createAccount(name: String, currencyCode: String, openingBalanceMinor: Int64) async throws -> Account
    func getAccounts() async throws -> [Account]
    func getTransactions(accountId: UUID) async throws -> [Transaction]
    func postTransaction(_ tx: Transaction, requireAuth: Bool) async throws -> Account
    func transfer(from: UUID, to: UUID, amountMinor: Int64, requireAuth: Bool, note: String?) async throws -> (from: Account, to: Account)
}

public actor BankingLedger: TransactionProcessor {
    private var snapshot: LedgerSnapshot
    private let storage: SecureStorage
    private let auth: AuthGate

    public init(storage: SecureStorage = EncryptedFileStorage(),
                auth: AuthGate = AllowAllAuthGate()) throws {
        self.storage = storage
        self.auth = auth
        self.snapshot = try storage.load()
        self.snapshot.accounts.sort { $0.name < $1.name }
    }

    private func persist() throws {
        try storage.save(snapshot)
    }

    public func createAccount(name: String, currencyCode: String = "USD", openingBalanceMinor: Int64) async throws -> Account {
        guard openingBalanceMinor >= 0 else { throw BankingError.invalidAmount }
        var account = Account(name: name, currencyCode: currencyCode, balanceMinor: openingBalanceMinor, updatedAt: Date())
        snapshot.accounts.append(account)
        snapshot.accounts.sort { $0.name < $1.name }
        snapshot.lastSequence &+= 1
        try persist()
        return account
    }

    public func getAccounts() async throws -> [Account] {
        snapshot.accounts
    }

    public func getTransactions(accountId: UUID) async throws -> [Transaction] {
        snapshot.transactions
            .filter { $0.accountId == accountId }
            .sorted { $0.createdAt > $1.createdAt }
    }

    private func indexOfAccount(_ id: UUID) -> Int? {
        snapshot.accounts.firstIndex(where: { $0.id == id })
    }

    private func apply(_ tx: Transaction) throws -> Account {
        guard tx.amountMinor > 0 else { throw BankingError.invalidAmount }
        guard let idx = indexOfAccount(tx.accountId) else { throw BankingError.accountNotFound }

        var acct = snapshot.accounts[idx]

        let delta: Int64
        switch tx.type {
        case .credit: delta = tx.amountMinor
        case .debit: delta = -tx.amountMinor
        }

        if delta < 0 && acct.balanceMinor + delta < 0 {
            throw BankingError.insufficientFunds
        }

        acct.balanceMinor &+= delta
        acct.updatedAt = Date()

        snapshot.accounts[idx] = acct
        snapshot.transactions.append(tx)
        snapshot.lastSequence &+= 1
        return acct
    }

    public func postTransaction(_ tx: Transaction, requireAuth: Bool = true) async throws -> Account {
        if requireAuth {
            let ok = await auth.evaluate(reason: "Authorize transaction")
            guard ok else { throw BankingError.authenticationFailed }
        }

        if snapshot.transactions.contains(where: { $0.id == tx.id }) {
            throw BankingError.duplicateTransaction
        }

        let updated = try apply(tx)
        try persist()
        return updated
    }

    public func transfer(from: UUID,
                         to: UUID,
                         amountMinor: Int64,
                         requireAuth: Bool = true,
                         note: String? = nil) async throws -> (from: Account, to: Account) {
        guard amountMinor > 0 else { throw BankingError.invalidAmount }
        guard from != to else { throw BankingError.operationNotAllowed }
        guard let fromIdx = indexOfAccount(from), let toIdx = indexOfAccount(to) else { throw BankingError.accountNotFound }

        let fromAcct = snapshot.accounts[fromIdx]
        let toAcct = snapshot.accounts[toIdx]
        guard fromAcct.currencyCode == toAcct.currencyCode else { throw BankingError.currencyMismatch }

        if requireAuth {
            let ok = await auth.evaluate(reason: "Authorize transfer")
            guard ok else { throw BankingError.authenticationFailed }
        }

        let now = Date()
        let debit = Transaction(accountId: from, type: .debit, amountMinor: amountMinor, merchant: nil, note: note, createdAt: now)
        let credit = Transaction(accountId: to, type: .credit, amountMinor: amountMinor, merchant: nil, note: note, createdAt: now)

        if snapshot.transactions.contains(where: { $0.id == debit.id || $0.id == credit.id }) {
            throw BankingError.duplicateTransaction
        }

        _ = try apply(debit)
        let updatedTo = try apply(credit)

        let updatedFrom = snapshot.accounts[fromIdx]
        _ = updatedTo

        try persist()
        return (from: updatedFrom, to: snapshot.accounts[toIdx])
    }
}

