        navigationItem.rightBarButtonItem = UIBarButtonItem(title: "Add", style: .plain, target: self, action: #selector(addDemoData))
        navigationItem.leftBarButtonItem = UIBarButtonItem(title: "Refresh", style: .plain, target: self, action: #selector(refresh))

        Task { await reload() }
    }

    @objc private func refresh() {
        Task { await reload() }
    }

    private func reload() async {
        do {
            let list = try await ledger.getAccounts()
            await MainActor.run {
                self.accounts = list
                self.tableView.reloadData()
            }
        } catch {
            await MainActor.run { self.presentError(error) }
        }
    }

    @objc private func addDemoData() {
        Task {
            do {
                if (try await ledger.getAccounts()).isEmpty {
                    _ = try await ledger.createAccount(name: "Checking", currencyCode: "USD", openingBalanceMinor: 250_00)
                    _ = try await ledger.createAccount(name: "Savings", currencyCode: "USD", openingBalanceMinor: 1500_00)
                } else {
                    let list = try await ledger.getAccounts()
                    if let first = list.first {
                        let tx = Transaction(accountId: first.id, type: .debit, amountMinor: 12_34, merchant: "Coffee Shop", note: "Latte")
                        _ = try await ledger.postTransaction(tx, requireAuth: false)
                    }
                }
                await reload()
            } catch {
                await MainActor.run { self.presentError(error) }
            }
        }
    }

