        navigationController?.pushViewController(vc, animated: true)
    }
}

public final class TransactionsViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    private let ledger: BankingLedger
    private var account: Account
    private var transactions: [Transaction] = []
    private let tableView = UITableView(frame: .zero, style: .insetGrouped)

    public init(ledger: BankingLedger, account: Account) {
        self.ledger = ledger
        self.account = account
        super.init(nibName: nil, bundle: nil)
        self.title = account.name
    }

    public required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    public override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.dataSource = self
        tableView.delegate = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "tx")
        view.addSubview(tableView)

        NSLayoutConstraint.activate([
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])

        navigationItem.rightBarButtonItems = [
            UIBarButtonItem(title: "Credit", style: .plain, target: self, action: #selector(addCredit)),
            UIBarButtonItem(title: "Debit", style: .plain, target: self, action: #selector(addDebit))
        ]

        Task { await reload() }
    }

    private func reload() async {
        do {
            let list = try await ledger.getTransactions(accountId: account.id)
            let accounts = try await ledger.getAccounts()
            if let updated = accounts.first(where: { $0.id == account.id }) {
                account = updated
            }
            await MainActor.run {
                self.transactions = list
                self.tableView.reloadData()
                self.updateHeader()
            }
        } catch {
            await MainActor.run { self.presentError(error) }
        }
    }

    private func updateHeader() {
        let header = UIHostingHeaderView(text: "Balance: \(Money.format(minor: account.balanceMinor, currencyCode: account.currencyCode))")
        header.frame.size.height = 44
        tableView.tableHeaderView = header
    }

    @objc private func addDebit() {
        Task { await promptAmountAndPost(type: .debit) }
    }

    @objc private func addCredit() {
        Task { await promptAmountAndPost(type: .credit) }
    }

    private func promptAmountAndPost(type: TransactionType) async {
        await MainActor.run {
            let title = type == .debit ? "New Debit" : "New Credit"
            let alert = UIAlertController(title: title, message: "Enter amount", preferredStyle: .alert)
            alert.addTextField { tf in
                tf.placeholder = "Amount (e.g. 12.34)"
                tf.keyboardType = .decimalPad
            }
            alert.addTextField { tf in
                tf.placeholder = "Merchant (optional)"
            }
            alert.addTextField { tf in
                tf.placeholder = "Note (optional)"
            }
            alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
            alert.addAction(UIAlertAction(title: "Post", style: .default) { [weak self] _ in
                guard let self else { return }
                let amountText = alert.textFields?[0].text ?? ""
                let merchant = alert.textFields?[1].text
                let note = alert.textFields?[2].text
                Task {
                    do {
                        let minor = Self.parseMinor(amountText)
                        let tx = Transaction(accountId: self.account.id, type: type, amountMinor: minor, merchant: merchant?.isEmpty == true ? nil : merchant, note: note?.isEmpty == true ? nil : note)
                        _ = try await self.ledger.postTransaction(tx, requireAuth: false)
                        await self.reload()
                    } catch {
                        await MainActor.run { self.presentError(error) }
                    }
                }
            })
            self.present(alert, animated: true)
        }
    }

    private static func parseMinor(_ s: String) -> Int64 {
        let trimmed = s.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalized = trimmed.replacingOccurrences(of: ",", with: ".")
        let parts = normalized.split(separator: ".", omittingEmptySubsequences: false)
        if parts.count == 1 {
            let whole = Int64(parts[0]) ?? 0
            return whole * 100
        }
        let whole = Int64(parts[0]) ?? 0
        let fracRaw = String(parts[1])
        let frac2 = (fracRaw + "00").prefix(2)
        let frac = Int64(frac2) ?? 0
        return whole * 100 + (whole >= 0 ? frac : -frac)
    }

    public func numberOfSections(in tableView: UITableView) -> Int { 1 }
    public func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int { transactions.count }

    public func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "tx", for: indexPath)
        let tx = transactions[indexPath.row]
        var config = cell.defaultContentConfiguration()
        let sign = tx.type == .debit ? "-" : "+"
        config.text = "\(sign)\(Money.format(minor: tx.amountMinor, currencyCode: account.currencyCode))"
        let merchant = tx.merchant ?? "Transaction"
        let date = DateFormatter.localizedString(from: tx.createdAt, dateStyle: .medium, timeStyle: .short)
        config.secondaryText = "\(merchant) • \(date)"
        cell.contentConfiguration = config
        return cell
    }

    private func presentError(_ error: Error) {
        let alert = UIAlertController(title: "Error", message: (error as? LocalizedError)?.errorDescription ?? error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

