        let storage = EncryptedFileStorage()
        let auth: AuthGate = requireLocalAuth ? LocalAuthGate() : AllowAllAuthGate()
        return try BankingLedger(storage: storage, auth: auth)
    }

    #if canImport(UIKit)
    public static func makeRootViewController(requireLocalAuth: Bool = false) throws -> UIViewController {
        let ledger = try makeLedger(requireLocalAuth: requireLocalAuth)
        let root = BankingModuleViewController(ledger: ledger)
        return UINavigationController(rootViewController: root)
    }
    #endif
}